# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, request, render_template
app = Flask(__name__)

@app.route('/welcome', methods=['GET'])
def welcome():
    name = request.args.get('name')
    bio = request.args.get('bio')
    location = request.args.get('location')
    status_message = request.args.get('status')

    # Simple formatting for bold and italic text in the bio and status message
    bold_format = '<b>{}</b>'
    italic_format = '<i>{}</i>'

    formatted_bio = ''
    formatted_status = ''

    for word in bio.split(' '):
        if word.startswith('**'):
            formatted_bio += bold_format.format(word[2:]) + ' '
        elif word.startswith('__'):
            formatted_bio += italic_format.format(word[2:]) + ' '
        else:
            formatted_bio += word + ' '

    for word in status_message.split(' '):
        if word.startswith('**'):
            formatted_status += bold_format.format(word[2:]) + ' '
        elif word.startswith('__'):
            formatted_status += italic_format.format(word[2:]) + ' '
        else:
            formatted_status += word + ' '

    return render_template('welcome.html', name=name, bio=formatted_bio, location=location, status=formatted_status)

if __name__ == '__main__':
    app.run(debug=True)